import test from 'node:test';
import assert from 'node:assert/strict';

import { CircuitBreaker } from '../src/circuit-breaker.mjs';
import { ClientInputError } from '../src/client-errors.mjs';
import { callService } from '../src/service-client.mjs';

test('only one recovery trial receives admission', () => {
  const breaker = new CircuitBreaker({ threshold: 1, cooldownMs: 10 });
  breaker.failure(0);
  assert.equal(breaker.canRequest(10), true);
  assert.equal(breaker.canRequest(10), false);
});

test('local validation does not count as backend health evidence', async () => {
  const breaker = new CircuitBreaker({ threshold: 1, cooldownMs: 10 });
  await assert.rejects(
    callService(async () => { throw new ClientInputError('bad request'); }, breaker, () => 0),
    ClientInputError
  );
  assert.deepEqual(breaker.snapshot(), { state: 'closed', failures: 0, openedAt: null });
});
